-- ----------------------------
-- Table structure for crawler_standings
-- ----------------------------
DROP TABLE IF EXISTS `crawler_standings`;
CREATE TABLE `crawler_standings`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `league_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联赛名称',
  `league_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联赛ID',
  `season` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '赛季，如 2023/2024',
  `team_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '球队名称',
  `team_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '球队ID',
  `team_logo` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '球队Logo',
  `rank` int(11) NULL DEFAULT NULL COMMENT '排名',
  `played` int(11) NULL DEFAULT 0 COMMENT '场次',
  `wins` int(11) NULL DEFAULT 0 COMMENT '胜',
  `draws` int(11) NULL DEFAULT 0 COMMENT '平',
  `losses` int(11) NULL DEFAULT 0 COMMENT '负',
  `goals_for` int(11) NULL DEFAULT 0 COMMENT '进球',
  `goals_against` int(11) NULL DEFAULT 0 COMMENT '失球',
  `goal_difference` int(11) NULL DEFAULT 0 COMMENT '净胜球',
  `points` int(11) NULL DEFAULT 0 COMMENT '积分',
  `source` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'zq123' COMMENT '数据来源',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_league_season`(`league_id`, `season`) USING BTREE,
  INDEX `idx_rank`(`rank`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 41 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '爬取的积分榜数据表' ROW_FORMAT = Dynamic;

