-- ----------------------------
-- Table structure for t_fixture_cache
-- ----------------------------
DROP TABLE IF EXISTS `t_fixture_cache`;
CREATE TABLE `t_fixture_cache`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '缓存ID',
  `fixture_id` bigint(20) NOT NULL COMMENT '比赛ID',
  `league_id` bigint(20) NULL DEFAULT NULL COMMENT '联赛ID',
  `league_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联赛名称',
  `home_team_id` bigint(20) NOT NULL COMMENT '主队ID',
  `home_team_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '主队名称',
  `away_team_id` bigint(20) NOT NULL COMMENT '客队ID',
  `away_team_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客队名称',
  `match_time` datetime NOT NULL COMMENT '比赛时间',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '状态',
  `home_goals` int(11) NULL DEFAULT NULL COMMENT '主队进球',
  `away_goals` int(11) NULL DEFAULT NULL COMMENT '客队进球',
  `round` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '轮次',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_fixture_id`(`fixture_id`) USING BTREE,
  INDEX `idx_match_time`(`match_time`) USING BTREE,
  INDEX `idx_league_id`(`league_id`) USING BTREE,
  INDEX `idx_home_team`(`home_team_id`) USING BTREE,
  INDEX `idx_away_team`(`away_team_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '比赛信息缓存表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_fixture_cache
-- ----------------------------

-- ----------------------------
-- Table structure for t_match_admin_override
-- ----------------------------
DROP TABLE IF EXISTS `t_match_admin_override`;
CREATE TABLE `t_match_admin_override`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `fixture_id` bigint(20) NOT NULL COMMENT '比赛ID',
  `league_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '联赛',
  `home_team_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '主队',
  `away_team_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客队',
  `match_time` datetime NULL DEFAULT NULL COMMENT '比赛时间',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '状态',
  `home_score` int(11) NULL DEFAULT NULL COMMENT '主队进球',
  `away_score` int(11) NULL DEFAULT NULL COMMENT '客队进球',
  `note` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `updated_by` bigint(20) NULL DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_fixture_id`(`fixture_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '比赛人工维护表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_match_admin_override
-- ----------------------------

-- ----------------------------
-- Table structure for t_news_article
-- ----------------------------
DROP TABLE IF EXISTS `t_news_article`;
CREATE TABLE `t_news_article`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '资讯ID',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标题',
  `subtitle` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '副标题',
  `summary` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '摘要',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '正文内容',
  `content_html` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '正文HTML',
  `cover_image` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '封面图',
  `source_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '来源站点名称',
  `source_url` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '来源URL',
  `source_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'crawler' COMMENT '来源类型:crawler/api/manual',
  `author` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '作者',
  `category` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '资讯' COMMENT '分类',
  `league_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联赛名称',
  `league_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联赛ID',
  `match_id` bigint(20) NULL DEFAULT NULL COMMENT '关联比赛ID',
  `team_id` bigint(20) NULL DEFAULT NULL COMMENT '关联球队ID',
  `is_hot` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否热门',
  `is_featured` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否焦点推荐',
  `is_top` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否置顶',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PUBLISHED' COMMENT '状态:DRAFT/PUBLISHED/HIDDEN/DELETED',
  `publish_time` datetime NULL DEFAULT NULL COMMENT '发布时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category`(`category`) USING BTREE,
  INDEX `idx_league_id`(`league_id`) USING BTREE,
  INDEX `idx_match_id`(`match_id`) USING BTREE,
  INDEX `idx_team_id`(`team_id`) USING BTREE,
  INDEX `idx_status_publish_time`(`status`, `publish_time`) USING BTREE,
  INDEX `idx_is_hot_featured_top`(`is_hot`, `is_featured`, `is_top`) USING BTREE,
  FULLTEXT INDEX `ft_title_summary_content`(`title`, `summary`, `content`)
) ENGINE = InnoDB AUTO_INCREMENT = 1004 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '新闻资讯主表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_news_article
-- ----------------------------
INSERT INTO `t_news_article` VALUES (1, '英超争冠进入白热化阶段', '关键战役将决定冠军归属', '豪门之间的直接对话成为赛季转折点。', '<p>英超赛程进入最后冲刺阶段，多支球队在积分榜上紧咬不放。</p><p>从近期状态来看，争冠队伍的伤病情况和替补席深度将成为胜负关键。</p><p>本轮焦点战不仅影响三分归属，也会对后续排兵布阵产生连锁反应。</p>', '<p>英超赛程进入最后冲刺阶段，多支球队在积分榜上紧咬不放。</p><p>从近期状态来看，争冠队伍的伤病情况和替补席深度将成为胜负关键。</p><p>本轮焦点战不仅影响三分归属，也会对后续排兵布阵产生连锁反应。</p>', 'https://images.unsplash.com/photo-1518091043644-c1d4457512c6?auto=format&fit=crop&w=1200&q=80', 'System', NULL, 'manual', '系统编辑部', '战报', '英超', '39', NULL, NULL, 1, 1, 1, 'PUBLISHED', '2026-05-27 18:26:55', '2026-05-27 17:16:19', '2026-05-27 20:28:51');
INSERT INTO `t_news_article` VALUES (2, '欧冠八强对阵看点', '控球压制与快速反击的博弈', '不同风格球队的碰撞，让战术对位与细节执行成为系列赛关键。', '<p>欧冠进入高强度淘汰赛阶段，比赛节奏和临场应变将极大考验教练组。</p><p>拥有高效转换能力的球队，往往能在强强对话中占据先机。</p><p>定位球和边路冲击也可能成为打破僵局的重要武器。</p>', '<p>欧冠进入高强度淘汰赛阶段，比赛节奏和临场应变将极大考验教练组。</p><p>拥有高效转换能力的球队，往往能在强强对话中占据先机。</p><p>定位球和边路冲击也可能成为打破僵局的重要武器。</p>', 'https://images.unsplash.com/photo-1522778119026-d647f0596c20?auto=format&fit=crop&w=1200&q=80', 'System', NULL, 'manual', '赛事观察员', '前瞻', '欧冠', '2', NULL, NULL, 1, 1, 0, 'PUBLISHED', '2026-05-27 18:26:55', '2026-05-27 17:16:19', '2026-05-27 20:28:51');
INSERT INTO `t_news_article` VALUES (3, '夏窗转会观察', '哪些球队会率先完成补强', '管理层的决策窗口已经开启，针对性补强将直接影响下赛季竞争力。', '<p>在转会市场中，效率和精准度比单纯的投入更重要。</p><p>部分球队需要补强中前场创造力，而另一些球队则急需补上防线漏洞。</p><p>随着窗口推进，价格、薪资结构与阵容平衡将持续影响交易走向。</p>', '<p>在转会市场中，效率和精准度比单纯的投入更重要。</p><p>部分球队需要补强中前场创造力，而另一些球队则急需补上防线漏洞。</p><p>随着窗口推进，价格、薪资结构与阵容平衡将持续影响交易走向。</p>', 'https://images.unsplash.com/photo-1521412644187-c49fa049e84d?auto=format&fit=crop&w=1200&q=80', 'System', NULL, 'manual', '转会中心', '转会', '综合', NULL, NULL, NULL, 0, 1, 0, 'PUBLISHED', '2026-05-27 18:26:55', '2026-05-27 17:16:19', '2026-05-27 18:26:55');
INSERT INTO `t_news_article` VALUES (4, '2026世界杯倒计时：墨西哥揭幕战迎战南非', '东道主首秀引关注', '世界杯将于6月11日在阿兹特卡球场拉开帷幕', '<p>墨西哥作为东道主之一，将在揭幕战中迎战南非。球迷高度期待...</p><p>双方历史交锋及战术分析...</p>', '<p>墨西哥作为东道主之一，将在揭幕战中迎战南非。球迷高度期待...</p><p>双方历史交锋及战术分析...</p>', 'https://images.unsplash.com/photo-1518091043644-c1d4457512c6?auto=format&fit=crop&w=1200&q=80', 'FIFA', NULL, 'manual', '世界杯观察员', '前瞻', '世界杯', 'WC', 2007, NULL, 1, 1, 1, 'PUBLISHED', '2026-05-28 14:18:18', '2026-05-28 14:18:18', '2026-05-28 14:18:18');
INSERT INTO `t_news_article` VALUES (5, '美国国家队世界杯前热身：对阵土耳其', '东道主备战关键战', '6月3日重要友谊赛检验阵容', '<p>美国队将在本土迎来土耳其的挑战，为世界杯小组赛蓄力...</p>', '<p>美国队将在本土迎来土耳其的挑战，为世界杯小组赛蓄力...</p>', 'https://images.unsplash.com/photo-1522778119026-d647f0596c20?auto=format&fit=crop&w=1200&q=80', 'ESPN', NULL, 'manual', '赛事编辑', '前瞻', '国际友谊赛', 'FRIENDLY', 2005, NULL, 1, 1, 0, 'PUBLISHED', '2026-05-28 14:18:18', '2026-05-28 14:18:18', '2026-05-28 14:18:18');
INSERT INTO `t_news_article` VALUES (6, '伊朗 vs 冈比亚：世界杯前最后热身', '亚洲与非洲球队对话', '5月29日国际友谊赛看点', '<p>两队均在为世界杯做最后准备...</p>', '<p>两队均在为世界杯做最后准备...</p>', 'https://images.unsplash.com/photo-1521412644187-c49fa049e84d?auto=format&fit=crop&w=1200&q=80', 'System', NULL, 'manual', '系统编辑部', '前瞻', '国际友谊赛', 'FRIENDLY', 2001, NULL, 0, 1, 0, 'PUBLISHED', '2026-05-28 14:18:18', '2026-05-28 14:18:18', '2026-05-28 14:18:18');
INSERT INTO `t_news_article` VALUES (7, '世界杯小组赛首轮前瞻：加拿大 vs 波黑', '北美 vs 欧洲球队碰撞', '6月12日多场重磅对决', '<p>东道主加拿大将在主场迎来欧洲球队挑战...</p>', '<p>东道主加拿大将在主场迎来欧洲球队挑战...</p>', 'https://images.unsplash.com/photo-1518091043644-c1d4457512c6?auto=format&fit=crop&w=1200&q=80', 'FIFA', NULL, 'manual', '世界杯中心', '前瞻', '世界杯', 'WC', 2009, NULL, 1, 0, 0, 'PUBLISHED', '2026-05-28 14:18:18', '2026-05-28 14:18:18', '2026-05-28 14:18:18');
INSERT INTO `t_news_article` VALUES (1001, '世界杯即将开赛，赛程正式公布', '48队时代开启，赛程已进入倒计时', '世界杯赛程已经公布，球迷可以提前关注揭幕战、强强对话和各组出线形势。', '随着 2026 年世界杯赛程公开，球迷的关注焦点已经从联赛休赛期转向国家队赛事。本届赛事规模扩大，赛程密集，首轮小组赛和后续淘汰赛都充满看点。对于预测系统来说，这类赛前数据是非常重要的内容补充。', '<p>随着 2026 年世界杯赛程公开，球迷的关注焦点已经从联赛休赛期转向国家队赛事。</p><p>本届赛事规模扩大，赛程密集，首轮小组赛和后续淘汰赛都充满看点。</p><p>对于预测系统来说，这类赛前数据是非常重要的内容补充。</p>', 'https://images.unsplash.com/photo-1518091043644-c1d4457512c6?auto=format&fit=crop&w=1200&q=80', 'FIFA', 'https://www.fifa.com/en/tournaments/mens/worldcup/canadamexicousa2026/articles/match-schedule-fixtures-results-teams-stadiums', 'manual', '系统编辑部', '前瞻', '2026世界杯', 'WC2026', NULL, NULL, 1, 1, 1, 'PUBLISHED', '2026-05-28 14:24:40', '2026-05-28 14:24:40', '2026-05-29 21:52:50');
INSERT INTO `t_news_article` VALUES (1002, '国际友谊赛密集上演，世界杯前热身进入高峰', '多支国家队通过热身赛调整状态', '休赛期并不意味着没有足球，国家队热身赛和备战新闻依然值得持续关注。', '<p>在世界杯临近开赛之前，多支国家队通过热身赛检验阵容和状态。</p><p>这些比赛虽然不在正式大赛中，但对于后续战术磨合和球员状态判断非常重要。</p>', '<p>在世界杯临近开赛之前，多支国家队通过热身赛检验阵容和状态。</p><p>这些比赛虽然不在正式大赛中，但对于后续战术磨合和球员状态判断非常重要。</p>', 'https://images.unsplash.com/photo-1508098682722-e99c43a406b2?auto=format&fit=crop&w=1200&q=80', 'System', NULL, 'manual', '系统编辑部', '战报', '国际友谊赛', 'FRIENDLY', NULL, NULL, 0, 1, 0, 'PUBLISHED', '2026-05-28 14:24:40', '2026-05-28 14:24:40', '2026-05-28 14:24:40');
INSERT INTO `t_news_article` VALUES (1003, '美国队与土耳其热身赛值得关注', '东道主备战状态成为焦点', '世界杯前的热身赛不仅能检验阵容，也能帮助我们观察东道主的备战情况。', '<p>美国队和土耳其这样的比赛，往往能体现球队的排兵布阵、替补深度以及临场调整能力。</p><p>对于赛前分析与预测系统来说，这类比赛具备很高的参考价值。</p>', '<p>美国队和土耳其这样的比赛，往往能体现球队的排兵布阵、替补深度以及临场调整能力。</p><p>对于赛前分析与预测系统来说，这类比赛具备很高的参考价值。</p>', 'https://images.unsplash.com/photo-1522778119026-d647f0596c20?auto=format&fit=crop&w=1200&q=80', 'System', NULL, 'manual', '赛事观察员', '前瞻', '世界杯', 'WC2026', NULL, NULL, 1, 1, 0, 'PUBLISHED', '2026-05-28 14:24:40', '2026-05-28 14:24:40', '2026-05-28 14:24:40');

-- ----------------------------
-- Table structure for t_news_article_comment
-- ----------------------------
DROP TABLE IF EXISTS `t_news_article_comment`;
CREATE TABLE `t_news_article_comment`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '评论ID',
  `article_id` bigint(20) NOT NULL COMMENT '资讯ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `parent_id` bigint(20) NULL DEFAULT NULL COMMENT '父评论ID',
  `content` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '评论内容',
  `like_count` int(11) NOT NULL DEFAULT 0 COMMENT '点赞数',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PUBLISHED' COMMENT '状态:PUBLISHED/HIDDEN/DELETED/PENDING',
  `ip_address` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'IP地址',
  `user_agent` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'UA',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_article_id`(`article_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_parent_id`(`parent_id`) USING BTREE,
  INDEX `idx_status_created_at`(`status`, `created_at`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '资讯评论表' ROW_FORMAT = Dynamic;

