-- ----------------------------
-- Table structure for t_news_push_log
-- ----------------------------
DROP TABLE IF EXISTS `t_news_push_log`;
CREATE TABLE `t_news_push_log`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '推送ID',
  `article_id` bigint(20) NULL DEFAULT NULL COMMENT '关联资讯ID',
  `fixture_id` bigint(20) NULL DEFAULT NULL COMMENT '关联比赛ID',
  `league_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联赛ID',
  `league_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联赛名称',
  `push_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '推送类型:PRE_MATCH/NEWS/HOT/ALERT',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '推送标题',
  `content` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '推送内容',
  `target_scope` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ALL' COMMENT '目标范围:ALL/LEAGUE/TEAM/USER',
  `target_value` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '目标值',
  `channel` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'IN_APP' COMMENT '渠道:IN_APP/PUSH/EMAIL/SMS',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING' COMMENT '状态:PENDING/SENT/FAILED',
  `sent_at` datetime NULL DEFAULT NULL COMMENT '发送时间',
  `failure_reason` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '失败原因',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_push_type_status`(`push_type`, `status`) USING BTREE,
  INDEX `idx_fixture_id`(`fixture_id`) USING BTREE,
  INDEX `idx_article_id`(`article_id`) USING BTREE,
  INDEX `idx_created_at`(`created_at`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '资讯推送日志表' ROW_FORMAT = Dynamic;

