-- ----------------------------
-- Table structure for t_prediction
-- ----------------------------
DROP TABLE IF EXISTS `t_prediction`;
CREATE TABLE `t_prediction`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '预测ID',
  `user_id` bigint(20) NULL DEFAULT NULL COMMENT '用户ID',
  `fixture_id` bigint(20) NOT NULL COMMENT '比赛ID',
  `home_team_id` bigint(20) NOT NULL COMMENT '主队ID',
  `away_team_id` bigint(20) NOT NULL COMMENT '客队ID',
  `home_team_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '主队名称(冗余)',
  `away_team_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客队名称(冗余)',
  `league_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联赛名称(冗余)',
  `result_label` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '预测结果: HOME_WIN/DRAW/AWAY_WIN',
  `home_win_prob` double NULL DEFAULT NULL COMMENT '主队胜概率',
  `draw_prob` double NULL DEFAULT NULL COMMENT '平局概率',
  `away_win_prob` double NULL DEFAULT NULL COMMENT '客队胜概率',
  `explanation` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '预测解释',
  `is_correct` tinyint(4) NULL DEFAULT NULL COMMENT '是否正确: 1=正确, 0=错误, NULL=未验证',
  `actual_result` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '实际结果',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '预测时间',
  `verified_at` datetime NULL DEFAULT NULL COMMENT '验证时间(比赛结束后)',
  `model_version` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_fixture_id`(`fixture_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_created_at`(`created_at`) USING BTREE,
  INDEX `idx_league_name`(`league_name`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '预测记录表' ROW_FORMAT = Dynamic;

