-- ----------------------------
-- Table structure for t_team_form
-- ----------------------------
DROP TABLE IF EXISTS `t_team_form`;
CREATE TABLE `t_team_form`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `team_id` bigint(20) NOT NULL COMMENT '球队ID',
  `fixture_id` bigint(20) NOT NULL COMMENT '比赛ID',
  `is_home` tinyint(4) NOT NULL COMMENT '是否主场',
  `opponent_id` bigint(20) NOT NULL COMMENT '对手ID',
  `goals` int(11) NOT NULL DEFAULT 0 COMMENT '进球',
  `conceded` int(11) NOT NULL DEFAULT 0 COMMENT '失球',
  `yellow_cards` int(11) NOT NULL DEFAULT 0 COMMENT '黄牌',
  `red_cards` int(11) NOT NULL DEFAULT 0 COMMENT '红牌',
  `result` tinyint(4) NOT NULL COMMENT '结果: 0=胜, 1=平, 2=负',
  `match_time` datetime NOT NULL COMMENT '比赛时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_team_id`(`team_id`) USING BTREE,
  INDEX `idx_fixture_id`(`fixture_id`) USING BTREE,
  INDEX `idx_match_time`(`match_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '球队历史战绩表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_team_form
-- ----------------------------

-- ----------------------------
-- Table structure for t_user
-- ----------------------------
DROP TABLE IF EXISTS `t_user`;
CREATE TABLE `t_user`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '用户ID',
  `username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户名',
  `password_hash` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '密码哈希(SHA256)',
  `role` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'USER' COMMENT '角色:USER/ADMIN',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态:ACTIVE/DISABLED',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_username`(`username`) USING BTREE,
  INDEX `idx_role`(`role`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_user
-- ----------------------------
INSERT INTO `t_user` VALUES (1, 'test', '8d969eef6ecad3c29a3a629280e686cf0c3f5d5a86aff3ca12020c923adc6c92', 'USER', 'ACTIVE', '2026-05-27 17:59:15');
INSERT INTO `t_user` VALUES (2, 'admin', '8d969eef6ecad3c29a3a629280e686cf0c3f5d5a86aff3ca12020c923adc6c92', 'ADMIN', 'ACTIVE', '2026-05-27 17:59:15');

-- ----------------------------
-- Table structure for t_user_favorite_match
-- ----------------------------
DROP TABLE IF EXISTS `t_user_favorite_match`;
CREATE TABLE `t_user_favorite_match`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '收藏ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `fixture_id` bigint(20) NOT NULL COMMENT '比赛ID',
  `home_team_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主队名称',
  `away_team_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '客队名称',
  `league_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联赛名称',
  `match_time` datetime NULL DEFAULT NULL COMMENT '比赛时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '收藏时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_fixture`(`user_id`, `fixture_id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_fixture_id`(`fixture_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户收藏比赛表' ROW_FORMAT = Dynamic;

