INSERT INTO `t_video_hub_item` VALUES (1, '曼城 vs 利物浦 - 经典对决集锦', '英超焦点战回顾', '收录双方比赛中的关键进球、精彩扑救与战术瞬间，适合赛后回看。', 'https://images.unsplash.com/photo-1518091043644-c1d4457512c6?auto=format&fit=crop&w=1200&q=80', 'https://www.youtube.com/', 'YouTube', '英超', '曼城', '利物浦', '2024-11-10 20:00:00', 'HIGHLIGHT', 1, 1, 100, 'PUBLISHED', 1, 1, '2026-05-30 14:48:31', '2026-05-30 14:48:31');
INSERT INTO `t_video_hub_item` VALUES (2, '皇马 vs 巴萨 - 国家德比回顾', '西甲德比集锦', '国家德比高光时刻与战术镜头回放，感受比赛节奏变化。', 'https://images.unsplash.com/photo-1522778119026-d647f0596c20?auto=format&fit=crop&w=1200&q=80', 'https://www.bilibili.com/', 'B站', '西甲', '皇马', '巴萨', '2024-10-26 21:00:00', 'REPLAY', 1, 1, 90, 'PUBLISHED', 1, 1, '2026-05-30 14:48:31', '2026-05-30 14:48:31');
INSERT INTO `t_video_hub_item` VALUES (3, '拜仁 vs 多特 - 德甲争冠关键战', '德甲焦点对话', '德甲强强对话精选片段，包含进攻配合与比赛节点。', 'https://images.unsplash.com/photo-1514911938617-5f0f8f07b4a9?auto=format&fit=crop&w=1200&q=80', 'https://sports.qq.com/', '腾讯体育', '德甲', '拜仁', '多特', '2024-09-14 19:30:00', 'HIGHLIGHT', 0, 1, 80, 'PUBLISHED', 1, 1, '2026-05-30 14:48:31', '2026-05-30 16:07:04');
INSERT INTO `t_video_hub_item` VALUES (4, '阿森纳 vs 热刺 - 北伦敦德比集锦', '英超德比大战', '德比战火爆对抗与进球瞬间，适合快速浏览精彩镜头。', 'https://images.unsplash.com/photo-1486286701208-1d58e9338013?auto=format&fit=crop&w=1200&q=80', 'https://www.youtube.com/', 'YouTube', '英超', '阿森纳', '热刺', '2024-08-31 18:30:00', 'HIGHLIGHT', 1, 0, 70, 'PUBLISHED', 1, 1, '2026-05-30 14:48:31', '2026-05-30 14:48:31');
INSERT INTO `t_video_hub_item` VALUES (5, '国米 vs AC米兰 - 米兰德比集锦', '意甲经典对决', '收录米兰德比中的进球与关键回合，适合赛后快速浏览。', 'https://images.unsplash.com/photo-1508098682722-e99c43a406b2?auto=format&fit=crop&w=1200&q=80', 'https://v.qq.com/', '腾讯视频', '意甲', '国际米兰', 'AC米兰', '2024-09-22 21:45:00', 'HIGHLIGHT', 0, 0, 60, 'PUBLISHED', 1, 1, '2026-05-30 14:48:31', '2026-05-30 14:48:31');
INSERT INTO `t_video_hub_item` VALUES (6, '日本 vs 韩国 - 亚洲杯回顾', '国家队赛事精选', '亚洲强队交锋集锦，突出比赛中的节奏变化和攻防转换。', 'https://images.unsplash.com/photo-1517466787929-bc90951d0974?auto=format&fit=crop&w=1200&q=80', 'https://www.youtube.com/', 'YouTube', '亚洲杯', '日本', '韩国', '2024-01-25 19:00:00', 'REPLAY', 0, 0, 50, 'PUBLISHED', 1, 1, '2026-05-30 14:48:31', '2026-05-30 14:48:31');
INSERT INTO `t_video_hub_item` VALUES (7, '曼联 vs 切尔西 - 赛后采访', '赛后访谈内容', '比赛结束后的球员与教练采访合集，适合深度了解比赛背景。', 'https://images.unsplash.com/photo-1574629810360-7efbbe195018?auto=format&fit=crop&w=1200&q=80', 'https://www.bilibili.com/', 'B站', '英超', '曼联', '切尔西', '2024-10-05 22:00:00', 'INTERVIEW', 0, 1, 85, 'DRAFT', 1, 1, '2026-05-30 14:48:31', '2026-05-30 14:48:31');

